node Meter { has name: str; has reading: int; has probed: bool = False; }

walker Scan {
    has limit: int;
    has hit: bool = False;
    can probe with Meter entry {
        if not here.probed {
            here.probed = True;
            if here.reading > self.limit { self.hit = True; disengage; }
            visit [-->];
        }
    }
}

def any_over_limit(spec: dict) -> bool {
    adj: dict = spec["adj"]; vals: dict = spec["vals"];
    reg: dict = {};
    for (src, outs) in adj.items() {
        if src not in reg { reg[src] = Meter(name=src, reading=vals[src]); }
        for o in outs { if o not in reg { reg[o] = Meter(name=o, reading=vals[o]); } }
    }
    for (src, outs) in adj.items() { for o in outs { reg[src] ++> reg[o]; } }
    agent = reg[spec["start"]] spawn Scan(limit=spec["limit"]);
    return agent.hit;
}

with entry { print(any_over_limit({"adj": {"a": ["b", "c"], "b": ["d"], "c": [], "d": []}, "vals": {"a": 2, "b": 3, "c": 4, "d": 9}, "start": "a", "limit": 5})); }

node Switch { has name: str; has on_state: bool; has checked: bool = False; }

walker Verify {
    has ok: bool = True;
    can check with Switch entry {
        if not here.checked {
            here.checked = True;
            if not here.on_state { self.ok = False; disengage; }
            visit [-->];
        }
    }
}

def all_flags_set(spec: dict) -> bool {
    adj: dict = spec["adj"]; flags: dict = spec["flags"];
    found: list = list(adj.keys());
    for group in adj.values() { for g in group { if g not in found { found.append(g); } } }
    sw: dict = {};
    for nm in found { sw[nm] = Switch(name=nm, on_state=flags[nm]); }
    for (src, group) in adj.items() { for g in group { sw[src] ++> sw[g]; } }
    w = sw[spec["start"]] spawn Verify();
    return w.ok;
}

with entry { print(all_flags_set({"adj": {"a": ["b"], "b": ["c"], "c": []}, "flags": {"a": True, "b": True, "c": True}, "start": "a"})); }

node Card { has name: str; has label: str; has used: bool = False; }

walker Tally {
    has target: str;
    has hits: int = 0;
    can mark with Card entry {
        if not here.used {
            here.used = True;
            if here.label == self.target { self.hits += 1; }
            visit [-->];
        }
    }
}

def count_label_matches(spec: dict) -> int {
    adj: dict = spec["adj"]; labels: dict = spec["labels"];
    names: list = list(adj.keys());
    for tgts in adj.values() { for t in tgts { if t not in names { names.append(t); } } }
    cards: dict = {};
    for nm in names { cards[nm] = Card(name=nm, label=labels[nm]); }
    for (src, tgts) in adj.items() { for t in tgts { cards[src] ++> cards[t]; } }
    wk = cards[spec["start"]] spawn Tally(target=spec["target"]);
    return wk.hits;
}

with entry { print(count_label_matches({"adj": {"a": ["b", "c"], "b": [], "c": ["d"], "d": []}, "labels": {"a": "red", "b": "blue", "c": "red", "d": "red"}, "start": "a", "target": "red"})); }

node Pod { has name: str; has load: int; has toured: bool = False; }

walker Seek {
    has best: int = -1;
    can weigh with Pod entry {
        if not here.toured {
            here.toured = True;
            if here.load > 0 and (self.best == -1 or here.load < self.best) { self.best = here.load; }
            visit [-->];
        }
    }
}

def min_over_positive(spec: dict) -> int {
    adj: dict = spec["adj"]; vals: dict = spec["vals"];
    pods: dict = {};
    for (src, outs) in adj.items() {
        if src not in pods { pods[src] = Pod(name=src, load=vals[src]); }
        for o in outs { if o not in pods { pods[o] = Pod(name=o, load=vals[o]); } }
    }
    for (src, outs) in adj.items() { for o in outs { pods[src] ++> pods[o]; } }
    agent = pods[spec["start"]] spawn Seek();
    return agent.best;
}

with entry { print(min_over_positive({"adj": {"a": ["b", "c"], "b": ["d"], "c": ["d"], "d": []}, "vals": {"a": 7, "b": -2, "c": 3, "d": 0}, "start": "a"})); }

node Reading { has name: str; has amt: int; has taken: bool = False; }

walker Bucket {
    has neg: int = 0;
    has zero: int = 0;
    has pos: int = 0;
    can sort_one with Reading entry {
        if not here.taken {
            here.taken = True;
            if here.amt < 0 { self.neg += 1; }
            elif here.amt == 0 { self.zero += 1; }
            else { self.pos += 1; }
            visit [-->];
        }
    }
}

def sign_bucket_counts(spec: dict) -> dict {
    adj: dict = spec["adj"]; vals: dict = spec["vals"];
    pool: dict = {};
    for (frm, dests) in adj.items() {
        if frm not in pool { pool[frm] = Reading(name=frm, amt=vals[frm]); }
        for d in dests { if d not in pool { pool[d] = Reading(name=d, amt=vals[d]); } }
    }
    for (frm, dests) in adj.items() { for d in dests { pool[frm] ++> pool[d]; } }
    w = pool[spec["start"]] spawn Bucket();
    return {"neg": w.neg, "zero": w.zero, "pos": w.pos};
}

with entry { print(sign_bucket_counts({"adj": {"a": ["b", "c"], "b": ["d"], "c": ["d"], "d": []}, "vals": {"a": -2, "b": 0, "c": 5, "d": 7}, "start": "a"})); }

